import java.util.ArrayList;
import java.util.Random;

class Solution extends SolBase {
    public int rand10(int n) {
        Random rand = new Random();
        ArrayList<Integer> result = new ArrayList<Integer>();

        for (int i = 0; i < n; i++) {
            int rand7 = rand.nextInt(7);
            result.add(rand7 + 1);
        }

        return result.get(0);
    }
}
